defmodule ElixirAppWeb.PageController do
  use ElixirAppWeb, :controller

  def index(conn, _params) do
    role = "admin" # this is user input

    query =
      Ecto.Adapters.SQL.query(Ecto.Adapters.SQL.Sandbox, "SELECT * FROM users WHERE role='#{role}'")

    case Repo.one(query) do
      nil ->
        conn
        |> put_flash(:error, "No users found with role #{role}")
        |> redirect(to: "/")

      user ->
        conn
        |> put_flash(:info, "#{user.name} is an admin")
        |> redirect(to: "/")
    end
  end
end

